import React, { useState, useEffect } from "react";
import { Field, Form } from "react-final-form";
import { InputField } from "../../../common/InputText";
import { Error, PageMode, required } from "../../../common/Utilitis";
import FacilityService from "../../services/facilities.service";
import CountryService from "../../services/countries.service";
import CityService from "../../services/cities.service";
import { useTranslation } from "react-i18next";
import { getFormControlUtilityClasses } from "@mui/material";
function AddUpdateForm(props) {
  const [t] = useTranslation();
  const { mode, selectedFacility, onClose } = props;
  const [isLoading, setIsLoading] = useState(false);
  const [isCityLoading, setIsCityLoading] = useState(false);
  // const [isCountryLoading, setIsCountryLoading] = useState(false);
  const [message, setMessage] = useState();
  const [countriesData, setCountriesData] = useState([]);
  const [citiesData, setCitiesData] = useState([]);
  const [selectedCountry, setSelectedCountry] = useState();
  const sleep = (ms) => new Promise((resolve) => setTimeout(resolve, ms));

  useEffect(async () => {
    setSelectedCountry(selectedFacility?.countryId);
    setIsCityLoading(true);
    const countryResponse = await CountryService.getAllCountries();
    const cityResponse = await CityService.getAllCities();
    setMessage(!!countryResponse?.message && countryResponse?.message);
    if (countryResponse.success) {
      setCountriesData(countryResponse.body);
    }
    if (cityResponse.success) {
      setCitiesData(cityResponse.body);
    }
    setIsCityLoading(false);
  }, []);

  const onSubmit = async (values) => {
    console.log(`onSubmit :: ${JSON.stringify(values, 0, 2)}`);
    setIsLoading(true);
    let response;
    if (mode === PageMode.Update) {
      response = await FacilityService.updateFacility(
        selectedFacility?.id,
        values
      );
    } else {
      response = await FacilityService.createFacility(values);
    }
    setIsLoading(false);
    if (!!!response.success && !response.success) {
      setMessage(!!response.message && response.message);
      return;
    }
    onClose(response.body);
  };

  const validate = async (values) => {
    const errors = {};
    if (!values.name) {
      errors.name = required;
    }
    if (!values.country) {
      errors.country = required;
    }
    if (!values.city) {
      errors.city = required;
    }
    return errors;
  };

  let form = (
    <Form
      validate={validate}
      onSubmit={onSubmit}
      initialValues={{
        name: selectedFacility?.name,
        country: selectedFacility?.countryId,
        city: selectedFacility?.cityId,
      }}
      render={({
        handleSubmit,
        onChange,
        submitError,
        form,
        submitting,
        pristine,
        values,
      }) => (
        <form onSubmit={handleSubmit} className="needs-validation" noValidate>
          {message && (
            <div className="invalid-feedback d-block mb-2">{message}</div>
          )}
          <div className="row form-row">
            <div className="col-12 col-md-6">
              <div className="form-group">
                <label>{t("Facility.Country")}</label>
                <Field name="country" showerrorbeside="true">
                  {({ input, meta }) => {
                    return (
                      <select
                        className="form-control select"
                        {...input.select}
                        defaultValue={values.country}
                        value={values.country}
                        onChange={(e) => {
                          input.onChange(e);
                          setSelectedCountry(e.target.value);
                        }}
                      >
                        <option value="">
                          {isCityLoading === true
                            ? t("loading")
                            : t("Facility.SelectCity")}
                        </option>
                        {countriesData?.map((val, index) => (
                          <option key={index} value={val.id}>
                            {val.name}
                          </option>
                        ))}
                      </select>
                    );
                  }}
                </Field>
                <Error name={"country"} showerrorbeside="true" />
              </div>
            </div>
            <div className="col-12 col-md-6">
              <div className="form-group">
                <label>{t("Facility.City")}</label>
                <Field name="city" showerrorbeside="true">
                  {({ input, meta }) => {
                    return (
                      <select
                        className="form-control select"
                        {...input.select}
                        defaultValue={values.city}
                        value={values.city}
                        onChange={(e) => {
                          input.onChange(e);
                        }}
                      >
                        <option value="">
                          {isCityLoading === true
                            ? t("loading")
                            : t("Facility.SelectCity")}
                        </option>
                        {citiesData
                          ?.filter((c) => c.country?.id === selectedCountry)
                          .map((val, index) => (
                            <option key={index} value={val.id}>
                              {val.name}
                            </option>
                          ))}
                      </select>
                    );
                  }}
                </Field>
                <Error name={"city"} showerrorbeside="true" />
              </div>
            </div>
            <div className="col-12 col-md-6">
              <div className="form-group">
                <label>{t("Facility.Name")}</label>
                <Field
                  name="name"
                  className="form-control floating"
                  type="text"
                  component={InputField}
                />
              </div>
            </div>
          </div>
          <div className="submit-section">
            <button
              type="submit"
              className="btn btn-primary submit-btn"
              disabled={isLoading}
            >
              {!isLoading ? t(`Facility.Save`) : ""}
              {isLoading && (
                <span className="spinner-border spinner-border-sm mb-1"></span>
              )}
            </button>
            <button
              className="btn btn-secondary submit-btn"
              onClick={(e) => {
                e.preventDefault();
                onClose(null);
              }}
            >
              {t("Facility.Close")}
            </button>
          </div>
        </form>
      )}
    />
  );

  return <div>{form}</div>;
}
export default AddUpdateForm;
